  1→import { useState, useEffect, useRef, useCallback } from "react";
  2→import { Sidebar } from "./features/repos/Sidebar";
  3→import { TitleBar } from "./components/TitleBar";
  4→import { TabBar } from "./components/TabBar";
  5→import { CheckpointList } from "./features/checkpoints/CheckpointList";
  6→import { TranscriptView } from "./features/transcripts/TranscriptView";
  7→import { DiffView, BranchDiffView } from "./features/diff/DiffView";
  8→import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
  9→import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
 10→import { TerminalPanel } from "./features/terminal/TerminalPanel";
 11→import type { TerminalPanelHandle } from "./features/terminal/TerminalPanel";
 12→import { useLiveUpdates } from "./hooks/use-live-updates";
 13→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 14→import { ArrowLeft, GitCommit } from "lucide-react";
 15→
 16→export interface Tab {
 17→  id: string;
 18→  branch: string;
 19→  repoPath: string;
 20→  worktree: WorktreeInfo | null;
 21→  hasActiveSession: boolean;
 22→}
 23→
 24→export default function App() {
 25→  const [tabs, setTabs] = useState<Tab[]>([
 26→    {
 27→      id: "main",
 28→      branch: "main",
 29→      repoPath: "",
 30→      worktree: null,
 31→      hasActiveSession: false,
 32→    },
 33→  ]);
 34→  const [activeTabId, setActiveTabId] = useState("main");
 35→  const [terminalHeight, setTerminalHeight] = useState(
 36→    () => Number(localStorage.getItem("entire:terminal-height")) || 220
 37→  );
 38→  const [isTerminalOpen, setIsTerminalOpen] = useState(
 39→    () => localStorage.getItem("entire:terminal-open") !== "false"
 40→  );
 41→  const [innerTab, setInnerTab] = useState<
 42→    "checkpoints" | "diff" | "insights"
 43→  >("checkpoints");
 44→  const [selectedCheckpoint, setSelectedCheckpoint] =
 45→    useState<CheckpointSummary | null>(null);
 46→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 47→    "transcript" | "diff" | "insights"
 48→  >("transcript");
 49→
 50→  const terminalRef = useRef<TerminalPanelHandle>(null);
 51→
 52→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
 53→
 54→  // Live updates — watch active repo for checkpoint/session changes
 55→  useLiveUpdates(activeTab.repoPath);
 56→
 57→  // Agent dispatch callback — opens terminal and sends prompt
 58→  const handleSendToAgent = useCallback(
 59→    (agent: string, prompt: string) => {
 60→      if (!isTerminalOpen) setIsTerminalOpen(true);
 61→      // Small delay to ensure terminal is mounted if it was closed
 62→      setTimeout(() => {
 63→        terminalRef.current?.launchAgentWithPrompt(agent, prompt);
 64→      }, isTerminalOpen ? 0 : 100);
 65→    },
 66→    [isTerminalOpen]
 67→  );
 68→
 69→  // Persist UI state to localStorage
 70→  useEffect(() => {
 71→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
 72→  }, [terminalHeight]);
 73→  useEffect(() => {
 74→    localStorage.setItem("entire:terminal-open", String(isTerminalOpen));
 75→  }, [isTerminalOpen]);
 76→
 77→  // Clear selected checkpoint when switching branch tabs
 78→  useEffect(() => {
 79→    setSelectedCheckpoint(null);
 80→    setCheckpointInnerTab("transcript");
 81→  }, [activeTabId]);
 82→
 83→  // Keyboard shortcuts
 84→  useEffect(() => {
 85→    function onKeyDown(e: KeyboardEvent) {
 86→      const meta = e.metaKey || e.ctrlKey;
 87→
 88→      // Cmd+K = focus search
 89→      if (meta && e.key === "k") {
 90→        e.preventDefault();
 91→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
 92→      }
 93→      // Ctrl+` = toggle terminal
 94→      if (e.ctrlKey && e.key === "`") {
 95→        e.preventDefault();
 96→        setIsTerminalOpen((v) => !v);
 97→      }
 98→      // Cmd+W = close active tab
 99→      if (meta && e.key === "w") {
100→        e.preventDefault();
101→        handleCloseTab(activeTabId);
102→      }
103→      // Cmd+1-9 = switch to tab by index
104→      if (meta && e.key >= "1" && e.key <= "9") {
105→        e.preventDefault();
106→        const idx = parseInt(e.key) - 1;
107→        if (idx < tabs.length) {
108→          setActiveTabId(tabs[idx].id);
109→        }
110→      }
111→      // Cmd+[ / Cmd+] = prev/next tab
112→      if (meta && e.key === "[") {
113→        e.preventDefault();
114→        const idx = tabs.findIndex((t) => t.id === activeTabId);
115→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
116→      }
117→      if (meta && e.key === "]") {
118→        e.preventDefault();
119→        const idx = tabs.findIndex((t) => t.id === activeTabId);
120→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
121→      }
122→      // Escape = deselect checkpoint
123→      if (e.key === "Escape" && selectedCheckpoint) {
124→        setSelectedCheckpoint(null);
125→      }
126→    }
127→    window.addEventListener("keydown", onKeyDown);
128→    return () => window.removeEventListener("keydown", onKeyDown);
129→  }, [activeTabId, tabs, selectedCheckpoint]);
130→
131→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
132→    const existing = tabs.find(
133→      (t) => t.branch === branch.name && t.repoPath === repoPath
134→    );
135→    if (existing) {
136→      setActiveTabId(existing.id);
137→    } else {
138→      const newTab: Tab = {
139→        id: `${repoPath}:${branch.name}`,
140→        branch: branch.name,
141→        repoPath,
142→        worktree: null,
143→        hasActiveSession: false,
144→      };
145→      setTabs([...tabs, newTab]);
146→      setActiveTabId(newTab.id);
147→    }
148→  }
149→
150→  function handleWorktreeSelect(wt: WorktreeInfo, repoPath: string) {
