  1→mod checkpoint;
  2→mod config;
  3→mod git;
  4→mod pty;
  5→mod session;
  6→mod trail;
  7→mod watcher;
  8→
  9→use std::collections::HashSet;
 10→use std::sync::Mutex;
 11→use tauri::{Emitter, State};
 12→
 13→struct AppState {
 14→    pty_manager: pty::PtyManager,
 15→    watched_repos: HashSet<String>,
 16→}
 17→
 18→#[tauri::command]
 19→fn list_repos() -> Result<Vec<git::RepoInfo>, String> {
 20→    let repo_paths = config::discover_repos();
 21→    let mut repos = Vec::new();
 22→    for path in repo_paths {
 23→        match git::get_repo_info(&path) {
 24→            Ok(info) => repos.push(info),
 25→            Err(e) => eprintln!("Skipping repo {}: {}", path, e),
 26→        }
 27→    }
 28→    Ok(repos)
 29→}
 30→
 31→#[tauri::command]
 32→fn list_checkpoints(
 33→    repo_path: String,
 34→    branch: String,
 35→) -> Result<Vec<checkpoint::CheckpointSummary>, String> {
 36→    let repo = git::open_repo(&repo_path)?;
 37→    checkpoint::list_checkpoints(&repo, &branch)
 38→}
 39→
 40→#[tauri::command]
 41→fn get_transcript(
 42→    repo_path: String,
 43→    checkpoint_id: String,
 44→    session_index: u32,
 45→) -> Result<Vec<session::TranscriptMessage>, String> {
 46→    let repo = git::open_repo(&repo_path)?;
 47→
 48→    let prefix = &checkpoint_id[..2];
 49→    let suffix = &checkpoint_id[2..];
 50→    let session_dir = format!("{}/{}/{}", prefix, suffix, session_index);
 51→
 52→    // Read the checkpoint metadata to find the actual transcript path
 53→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
 54→    let transcript_path = read_blob(&repo, &meta_path)
 55→        .ok()
 56→        .and_then(|meta_content| {
 57→            let meta: serde_json::Value = serde_json::from_str(&meta_content).ok()?;
 58→            let sessions = meta.get("sessions")?.as_array()?;
 59→            let session = sessions.get(session_index as usize)?;
 60→            session.get("transcript")?.as_str().map(|s| s.to_string())
 61→        });
 62→
 63→    // Build candidates: metadata path (may be absolute from tree root), then fallbacks
 64→    let mut candidates = Vec::new();
 65→    if let Some(ref path) = transcript_path {
 66→        // Paths from metadata may be absolute (leading /) — strip it for tree lookup
 67→        candidates.push(path.trim_start_matches('/').to_string());
 68→    }
 69→    candidates.push(format!("{}/full.jsonl", session_dir));
 70→    candidates.push(format!("{}/transcript.jsonl", session_dir));
 71→
 72→    for path in &candidates {
 73→        if let Ok(content) = read_blob(&repo, path) {
 74→            return Ok(session::read_transcript(&content));
 75→        }
 76→    }
 77→
 78→    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
 79→}
 80→
 81→/// Read a blob from the entire/checkpoints/v1 branch by path
 82→fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
 83→    let branch_ref = repo
 84→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
 85→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
 86→
 87→    let commit = branch_ref
 88→        .get()
 89→        .peel_to_commit()
 90→        .map_err(|e| format!("Failed to peel: {}", e))?;
 91→
 92→    let tree = commit
 93→        .tree()
 94→        .map_err(|e| format!("Failed to get tree: {}", e))?;
 95→
 96→    let entry = tree
 97→        .get_path(std::path::Path::new(path))
 98→        .map_err(|e| format!("Path not found: {}", e))?;
 99→
100→    let blob = repo
101→        .find_blob(entry.id())
102→        .map_err(|e| format!("Failed to read blob: {}", e))?;
103→
104→    std::str::from_utf8(blob.content())
105→        .map(|s| s.to_string())
106→        .map_err(|e| format!("Invalid UTF-8: {}", e))
107→}
108→
109→#[tauri::command]
110→fn list_sessions(repo_path: String) -> Result<Vec<session::SessionState>, String> {
111→    session::list_active_sessions(&repo_path)
112→}
113→
114→#[tauri::command]
115→fn spawn_agent(
116→    repo_path: String,
117→    agent: String,
118→    app: tauri::AppHandle,
119→    state: State<'_, Mutex<AppState>>,
120→) -> Result<String, String> {
121→    let app_handle = app.clone();
122→    let state = state.lock().map_err(|_| "State lock error".to_string())?;
123→
124→    state.pty_manager.spawn(&agent, &repo_path, move |session_id, data| {
125→        let _ = app_handle.emit("pty-output", serde_json::json!({
126→            "sessionId": session_id,
127→            "data": data,
128→        }));
129→    })
130→}
131→
132→#[tauri::command]
133→fn pty_input(
134→    session_id: String,
135→    data: String,
136→    state: State<'_, Mutex<AppState>>,
137→) -> Result<(), String> {
138→    let state = state.lock().map_err(|_| "State lock error".to_string())?;
139→    state.pty_manager.write(&session_id, data.as_bytes())
140→}
141→
142→#[tauri::command]
143→fn pty_resize(
144→    session_id: String,
145→    cols: u16,
146→    rows: u16,
147→    state: State<'_, Mutex<AppState>>,
148→) -> Result<(), String> {
149→    let state = state.lock().map_err(|_| "State lock error".to_string())?;
150→    state.pty_manager.resize(&session_id, cols, rows)
151→}
152→
153→#[tauri::command]
154→fn kill_pty(
155→    session_id: String,
156→    state: State<'_, Mutex<AppState>>,
157→) -> Result<(), String> {
158→    let state = state.lock().map_err(|_| "State lock error".to_string())?;
159→    state.pty_manager.kill(&session_id)
160→}
161→
