#[tauri::command]
fn get_transcript(
    repo_path: String,
    checkpoint_id: String,
    session_index: u32,
) -> Result<Vec<session::TranscriptMessage>, String> {
    let repo = git::open_repo(&repo_path)?;

    let prefix = &checkpoint_id[..2];
    let suffix = &checkpoint_id[2..];
    let session_dir = format!("{}/{}/{}", prefix, suffix, session_index);

    // Read the checkpoint metadata to find the actual transcript path
    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
    let transcript_path = read_blob(&repo, &meta_path)
        .ok()
        .and_then(|meta_content| {
            let meta: serde_json::Value = serde_json::from_str(&meta_content).ok()?;
            let sessions = meta.get("sessions")?.as_array()?;
            let session = sessions.get(session_index as usize)?;
            session.get("transcript")?.as_str().map(|s| s.to_string())
        });

    // Build candidates: metadata path (may be absolute from tree root), then fallbacks
    let mut candidates = Vec::new();
    if let Some(ref path) = transcript_path {
        // Paths from metadata may be absolute (leading /) — strip it for tree lookup
        candidates.push(path.trim_start_matches('/').to_string());
    }
    candidates.push(format!("{}/full.jsonl", session_dir));
    candidates.push(format!("{}/transcript.jsonl", session_dir));

    for path in &candidates {
        if let Ok(content) = read_blob(&repo, path) {
            return Ok(session::read_transcript(&content));
        }
    }

    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
}

/// Read a blob from the entire/checkpoints/v1 branch by path
fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
    let branch_ref = repo
        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
        .map_err(|e| format!("No checkpoint branch: {}", e))?;

    let commit = branch_ref
        .get()
        .peel_to_commit()
        .map_err(|e| format!("Failed to peel: {}", e))?;

    let tree = commit
        .tree()
        .map_err(|e| format!("Failed to get tree: {}", e))?;

    let entry = tree
        .get_path(std::path::Path::new(path))
        .map_err(|e| format!("Path not found: {}", e))?;

    let blob = repo
        .find_blob(entry.id())
        .map_err(|e| format!("Failed to read blob: {}", e))?;

    std::str::from_utf8(blob.content())
        .map(|s| s.to_string())
        .map_err(|e| format!("Invalid UTF-8: {}", e))
}

